package com.cognizant.billing.controller;import com.cognizant.billing.model.Bill;import com.cognizant.billing.repository.BillRepository;import org.springframework.web.bind.annotation.*;import java.util.List;@RestController @RequestMapping("/bills") public class BillController{private final BillRepository repo;public BillController(BillRepository repo){this.repo=repo;}@GetMapping public List<Bill> all(){return repo.findAll();}@GetMapping("/{id}") public Bill one(@PathVariable Long id){return repo.findById(id).orElseThrow();}@PostMapping public Bill create(@RequestBody Bill x){return repo.save(x);}}